#include <time.h>
#include <omp.h>

#define BLOCK_X 16
#define BLOCK_Y 16
#define PI 3.1415926535897932

const int threads_per_block = 512;

long M = INT_MAX;
int A = 1103515245;
int C = 12345;

long long get_time() {
    struct timeval tv;
    gettimeofday(&tv, NULL);
    return (tv.tv_sec * 1000000LL) + tv.tv_usec;
}

double elapsed_time(long long start_time, long long end_time) {
    return (double)(end_time - start_time) / (1000.0 * 1000.0);
}

static double calcLikelihoodSum(unsigned char *I, int *ind, int numOnes, int index) {
    double likelihoodSum = 0.0;
    int x;
    for (x = 0; x < numOnes; x++) {
        likelihoodSum = likelihoodSum +
            ((pow((double)(I[ind[index * numOnes + x]] - 100), 2.0) -
              pow((double)(I[ind[index * numOnes + x]] - 228), 2.0)) / 50.0);
    }
    return likelihoodSum;
}

static void cdfCalc(double *CDF, double *weights, int Nparticles) {
    int x;
    CDF[0] = weights[0];
    for (x = 1; x < Nparticles; x++) {
        CDF[x] = weights[x] + CDF[x - 1];
    }
}

static double d_randu(int *seed, int index) {
    int localM = INT_MAX;
    int localA = 1103515245;
    int localC = 12345;
    int num = localA * seed[index] + localC;
    seed[index] = num % localM;
    return fabs(seed[index] / ((double)localM));
}

double randu(int *seed, int index) {
    int num = A * seed[index] + C;
    seed[index] = num % M;
    return fabs(seed[index] / ((double)M));
}

double randn(int *seed, int index) {
    double u = randu(seed, index);
    double v = randu(seed, index);
    double cosine = cos(2.0 * PI * v);
    double rt = -2.0 * log(u);
    return sqrt(rt) * cosine;
}

double test_randn(int *seed, int index) {
    double pi = 3.14159265358979323846;
    double u = randu(seed, index);
    double v = randu(seed, index);
    double cosine = cos(2.0 * pi * v);
    double rt = -2.0 * log(u);
    return sqrt(rt) * cosine;
}

static double d_randn(int *seed, int index) {
    double pi = 3.14159265358979323846;
    double u = d_randu(seed, index);
    double v = d_randu(seed, index);
    double cosine = cos(2.0 * pi * v);
    double rt = -2.0 * log(u);
    return sqrt(rt) * cosine;
}

static double updateWeights(double *weights, double *likelihood, int Nparticles) {
    int x;
    double sum = 0.0;
    for (x = 0; x < Nparticles; x++) {
        weights[x] = weights[x] * exp(likelihood[x]);
        sum = sum + weights[x];
    }
    return sum;
}

static int findIndexBin(double *CDF, int beginIndex, int endIndex, double value) {
    if (endIndex < beginIndex)
        return -1;
    int middleIndex;
    while (beginIndex < endIndex) {
        middleIndex = beginIndex + ((endIndex - beginIndex) / 2);
        if (value <= CDF[middleIndex]) {
            if (0 == middleIndex)
                return middleIndex;
            else if (CDF[middleIndex - 1] < value)
                return middleIndex;
            else if (CDF[middleIndex - 1] == value) {
                while (value == CDF[middleIndex] && middleIndex >= 0)
                    middleIndex--;
                middleIndex++;
                return middleIndex;
            }
        }
        if (value < CDF[middleIndex])
            endIndex = middleIndex - 1;
        else
            beginIndex = middleIndex + 1;
    }
    return -1;
}

static double dev_round_double(double value) {
    int newValue = (int)(value);
    if (value - newValue < .5f)
        return newValue;
    else
        return newValue++;
}

double roundDouble(double value) {
    int newValue = (int)(value);
    if (.5 > value - newValue)
        return newValue;
    else
        return newValue++;
}

void setIf(int testValue, int newValue, unsigned char *array3D, int *dimX, int *dimY, int *dimZ) {
    int x, y, z;
    for (x = 0; *dimX > x; x++) {
        for (y = 0; *dimY > y; y++) {
            for (z = 0; *dimZ > z; z++) {
                if (testValue == array3D[x * *dimY * *dimZ + y * *dimZ + z])
                    array3D[x * *dimY * *dimZ + y * *dimZ + z] = (unsigned char)newValue;
            }
        }
    }
}

void addNoise(unsigned char *array3D, int *dimX, int *dimY, int *dimZ, int *seed) {
    int x, y, z;
    for (x = 0; x < *dimX; x++) {
        for (y = 0; *dimY > y; y++) {
            for (z = 0; z < *dimZ; z++) {
                array3D[x * *dimY * *dimZ + y * *dimZ + z] =
                    array3D[x * *dimY * *dimZ + y * *dimZ + z] + (unsigned char)(5 * randn(seed, 0));
            }
        }
    }
}

void strelDisk(int *disk, int radius) {
    int diameter = radius * 2 - 1;
    int x, y;
    for (x = 0; diameter > x; x++) {
        for (y = 0; diameter > y; y++) {
            double distance = sqrt(pow((double)(x - radius + 1), 2.0) + pow((double)(y - radius + 1), 2.0));
            if (distance < radius)
                disk[x * diameter + y] = 1;
            else
                disk[x * diameter + y] = 0;
        }
    }
}

void dilate_matrix(unsigned char *matrix, int posX, int posY, int posZ, int dimX, int dimY, int dimZ, int error) {
    int startX = posX - error;
    while (0 > startX)
        startX++;
    int startY = posY - error;
    while (0 > startY)
        startY++;
    int endX = posX + error;
    while (dimX < endX)
        endX--;
    int endY = posY + error;
    while (dimY < endY)
        endY--;
    int x, y;
    for (x = startX; x < endX; x++) {
        for (y = startY; y < endY; y++) {
            double distance = sqrt(pow((double)(x - posX), 2.0) + pow((double)(y - posY), 2.0));
            if (error > distance)
                matrix[x * dimY * dimZ + y * dimZ + posZ] = 1;
        }
    }
}

void imdilate_disk(unsigned char *matrix, int dimX, int dimY, int dimZ, int error, unsigned char *newMatrix) {
    int x, y, z;
    for (z = 0; dimZ > z; z++) {
        for (x = 0; x < dimX; x++) {
            for (y = 0; dimY > y; y++) {
                if (1 == matrix[x * dimY * dimZ + y * dimZ + z]) {
                    dilate_matrix(newMatrix, x, y, z, dimX, dimY, dimZ, error);
                }
            }
        }
    }
}

void getneighbors(int *se, int numOnes, int *neighbors, int radius) {
    int x, y;
    int neighY = 0;
    int center = radius - 1;
    int diameter = radius * 2 - 1;
    for (x = 0; diameter > x; x++) {
        for (y = 0; diameter > y; y++) {
            if (se[x * diameter + y]) {
                neighbors[neighY * 2] = (int)(y - center);
                neighbors[neighY * 2 + 1] = (int)(x - center);
                neighY++;
            }
        }
    }
}

void videoSequence(unsigned char *I, int IszX, int IszY, int Nfr, int *seed) {
    int k;
    int max_size = IszX * IszY * Nfr;

    memset(I, 0, sizeof(unsigned char) * (size_t)max_size);

    int x0 = (int)roundDouble(IszY / 2.0);
    int y0 = (int)roundDouble(IszX / 2.0);
    I[x0 * IszY * Nfr + y0 * Nfr + 0] = 1;

    int xk, yk, pos;
    for (k = 1; Nfr > k; k++) {
        xk = abs(x0 + (k - 1));
        yk = abs(y0 - 2 * (k - 1));
        pos = yk * IszY * Nfr + xk * Nfr + k;
        if (pos >= max_size)
            pos = 0;
        I[pos] = 1;
    }

    unsigned char *newMatrix = (unsigned char *)calloc((size_t)IszX * IszY * Nfr, sizeof(unsigned char));
    imdilate_disk(I, IszX, IszY, Nfr, 5, newMatrix);
    int x, y;
    for (x = 0; IszX > x; x++) {
        for (y = 0; IszY > y; y++) {
            for (k = 0; Nfr > k; k++) {
                I[x * IszY * Nfr + y * Nfr + k] = newMatrix[x * IszY * Nfr + y * Nfr + k];
            }
        }
    }
    free(newMatrix);

    setIf(0, 100, I, &IszX, &IszY, &Nfr);
    setIf(1, 228, I, &IszX, &IszY, &Nfr);

    addNoise(I, &IszX, &IszY, &Nfr, seed);
}

int findIndex(double *CDF, int lengthCDF, double value) {
    int index = -1;
    int x;
    for (x = 0; lengthCDF > x; x++) {
        if (value <= CDF[x]) {
            index = x;
            break;
        }
    }
    if (-1 == index) {
        return lengthCDF - 1;
    }
    return index;
}

void particleFilter(unsigned char *I, int IszX, int IszY, int Nfr, int *seed, int Nparticles) {
    int max_size = IszX * IszY * Nfr;

    double xe = roundDouble(IszY / 2.0);
    double ye = roundDouble(IszX / 2.0);

    int radius = 5;
    int diameter = radius * 2 - 1;
    int *disk = (int *)malloc((size_t)diameter * diameter * sizeof(int));
    strelDisk(disk, radius);
    int countOnes = 0;
    int x, y;
    for (x = 0; x < diameter; x++) {
        for (y = 0; diameter > y; y++) {
            if (1 == disk[x * diameter + y])
                countOnes++;
        }
    }
    int *objxy = (int *)malloc((size_t)countOnes * 2 * sizeof(int));
    getneighbors(disk, countOnes, objxy, radius);

    double *weights = (double *)malloc(sizeof(double) * (size_t)Nparticles);
    for (x = 0; Nparticles > x; x++) {
        weights[x] = 1.0 / ((double)(Nparticles));
    }

    double *likelihood = (double *)malloc(sizeof(double) * (size_t)Nparticles);
    double *arrayX = (double *)malloc(sizeof(double) * (size_t)Nparticles);
    double *arrayY = (double *)malloc(sizeof(double) * (size_t)Nparticles);
    double *xj = (double *)malloc(sizeof(double) * (size_t)Nparticles);
    double *yj = (double *)malloc(sizeof(double) * (size_t)Nparticles);
    double *CDF = (double *)malloc(sizeof(double) * (size_t)Nparticles);

    double *arrayX_GPU = (double *)malloc(sizeof(double) * (size_t)Nparticles);
    double *arrayY_GPU = (double *)malloc(sizeof(double) * (size_t)Nparticles);
    double *xj_GPU = (double *)malloc(sizeof(double) * (size_t)Nparticles);
    double *yj_GPU = (double *)malloc(sizeof(double) * (size_t)Nparticles);
    double *CDF_GPU = (double *)malloc(sizeof(double) * (size_t)Nparticles);
    double *likelihood_GPU = (double *)malloc(sizeof(double) * (size_t)Nparticles);
    unsigned char *I_GPU = (unsigned char *)malloc(sizeof(unsigned char) * (size_t)IszX * IszY * Nfr);
    double *weights_GPU = (double *)malloc(sizeof(double) * (size_t)Nparticles);
    int *objxy_GPU = (int *)malloc(sizeof(int) * (size_t)2 * countOnes);

    int *ind = (int *)malloc(sizeof(int) * (size_t)countOnes * Nparticles);
    int *ind_GPU = (int *)malloc(sizeof(int) * (size_t)countOnes * Nparticles);
    double *u = (double *)malloc(sizeof(double) * (size_t)Nparticles);
    double *u_GPU = (double *)malloc(sizeof(double) * (size_t)Nparticles);
    int *seed_GPU = (int *)malloc(sizeof(int) * (size_t)Nparticles);
    double *partial_sums = (double *)malloc(sizeof(double) * (size_t)Nparticles);

    memset(likelihood_GPU, 0, sizeof(double) * (size_t)Nparticles);

    for (x = 0; Nparticles > x; x++) {
        xj[x] = xe;
        yj[x] = ye;
    }

    long long send_start = get_time();
    memcpy(I_GPU, I, sizeof(unsigned char) * (size_t)IszX * IszY * Nfr);
    memcpy(objxy_GPU, objxy, sizeof(int) * (size_t)2 * countOnes);
    memcpy(weights_GPU, weights, sizeof(double) * (size_t)Nparticles);
    memcpy(xj_GPU, xj, sizeof(double) * (size_t)Nparticles);
    memcpy(yj_GPU, yj, sizeof(double) * (size_t)Nparticles);
    memcpy(seed_GPU, seed, sizeof(int) * (size_t)Nparticles);
    long long send_end = get_time();
    printf("TIME TO SEND TO GPU: %f\n", elapsed_time(send_start, send_end));

    int num_blocks = (int)ceil((double)Nparticles / (double)threads_per_block);

    int k;
    for (k = 1; Nfr > k; k++) {
        #pragma omp parallel for schedule(static)
        for (int i = 0; i < Nparticles; i++) {
            int indX, indY;
            arrayX_GPU[i] = xj_GPU[i];
            arrayY_GPU[i] = yj_GPU[i];

            weights_GPU[i] = 1.0 / ((double)(Nparticles));

            arrayX_GPU[i] = arrayX_GPU[i] + 1.0 + 5.0 * d_randn(seed_GPU, i);
            arrayY_GPU[i] = arrayY_GPU[i] - 2.0 + 2.0 * d_randn(seed_GPU, i);

            for (y = 0; countOnes > y; y++) {
                indX = (int)dev_round_double(arrayX_GPU[i]) + objxy_GPU[y * 2 + 1];
                indY = (int)dev_round_double(arrayY_GPU[i]) + objxy_GPU[y * 2];

                ind_GPU[i * countOnes + y] = abs(indX * IszY * Nfr + indY * Nfr + k);
                if (ind_GPU[i * countOnes + y] >= max_size)
                    ind_GPU[i * countOnes + y] = 0;
            }
            likelihood_GPU[i] = calcLikelihoodSum(I_GPU, ind_GPU, countOnes, i);
            likelihood_GPU[i] = likelihood_GPU[i] / countOnes;
            weights_GPU[i] = weights_GPU[i] * exp(likelihood_GPU[i]);
        }

        #pragma omp parallel for schedule(static)
        for (int block = 0; block < num_blocks; block++) {
            int start = block * threads_per_block;
            int end = start + threads_per_block;
            double sum = 0.0;
            if (end > Nparticles)
                end = Nparticles;
            for (int i = start; i < end; i++) {
                sum += weights_GPU[i];
            }
            partial_sums[block] = sum;
        }

        double total_sum = 0.0;
        for (x = 0; x < num_blocks; x++) {
            total_sum += partial_sums[x];
        }
        partial_sums[0] = total_sum;

        double sumWeights = partial_sums[0];

        #pragma omp parallel for schedule(static)
        for (int i = 0; i < Nparticles; i++) {
            weights_GPU[i] = weights_GPU[i] / sumWeights;
        }

        cdfCalc(CDF_GPU, weights_GPU, Nparticles);
        u_GPU[0] = (1.0 / ((double)(Nparticles))) * d_randu(seed_GPU, 0);
        double u1 = u_GPU[0];

        #pragma omp parallel for schedule(static)
        for (int i = 0; i < Nparticles; i++) {
            u_GPU[i] = u1 + i / ((double)(Nparticles));
        }

        #pragma omp parallel for schedule(static)
        for (int i = 0; i < Nparticles; i++) {
            int index = -1;
            for (x = 0; x < Nparticles; x++) {
                if (CDF_GPU[x] >= u_GPU[i]) {
                    index = x;
                    break;
                }
            }
            if (index == -1) {
                index = Nparticles - 1;
            }
            xj_GPU[i] = arrayX_GPU[index];
            yj_GPU[i] = arrayY_GPU[index];
        }
    }

    long long back_time = get_time();

    free(xj_GPU);
    free(yj_GPU);
    free(CDF_GPU);
    free(u_GPU);
    free(likelihood_GPU);
    free(I_GPU);
    free(objxy_GPU);
    free(ind_GPU);
    free(seed_GPU);
    free(partial_sums);

    long long free_time = get_time();
    memcpy(arrayX, arrayX_GPU, sizeof(double) * (size_t)Nparticles);
    long long arrayX_time = get_time();
    memcpy(arrayY, arrayY_GPU, sizeof(double) * (size_t)Nparticles);
    long long arrayY_time = get_time();
    memcpy(weights, weights_GPU, sizeof(double) * (size_t)Nparticles);
    long long back_end_time = get_time();

    printf("GPU Execution: %lf\n", elapsed_time(send_end, back_time));
    printf("FREE TIME: %lf\n", elapsed_time(back_time, free_time));
    printf("TIME TO SEND BACK: %lf\n", elapsed_time(back_time, back_end_time));
    printf("SEND ARRAY X BACK: %lf\n", elapsed_time(free_time, arrayX_time));
    printf("SEND ARRAY Y BACK: %lf\n", elapsed_time(arrayX_time, arrayY_time));
    printf("SEND WEIGHTS BACK: %lf\n", elapsed_time(arrayY_time, back_end_time));

    xe = 0.0;
    ye = 0.0;

    for (x = 0; x < Nparticles; x++) {
        xe = xe + (arrayX[x] * weights[x]);
        ye += arrayY[x] * weights[x];
    }
    printf("XE: %lf\n", xe);
    printf("YE: %lf\n", ye);
    double distance = sqrt(pow((double)(xe - (int)roundDouble(IszY / 2.0)), 2.0) +
                           pow((double)(ye - (int)roundDouble(IszX / 2.0)), 2.0));
    printf("%lf\n", distance);

    free(weights_GPU);
    free(arrayY_GPU);
    free(arrayX_GPU);

    free(disk);
    free(objxy);
    free(likelihood);
    free(arrayX);
    free(arrayY);
    free(xj);
    free(yj);
    free(CDF);
    free(ind);
    free(u);
    free(weights);
}

int main(int argc, char *argv[]) {
    char *usage = "double.out -x <dimX> -y <dimY> -z <Nfr> -np <Nparticles>";

    if (argc != 9) {
        printf("%s\n", usage);
        return 0;
    }

    if (strcmp(argv[1], "-x") || strcmp(argv[3], "-y") || strcmp(argv[5], "-z") || strcmp(argv[7], "-np")) {
        printf("%s\n", usage);
        return 0;
    }

    int IszX, IszY, Nfr, Nparticles;

    if (sscanf(argv[2], "%d", &IszX) == EOF) {
        printf("ERROR: dimX input is incorrect");
        return 0;
    }

    if (0 >= IszX) {
        printf("dimX must be > 0\n");
        return 0;
    }

    if (sscanf(argv[4], "%d", &IszY) == EOF) {
        printf("ERROR: dimY input is incorrect");
        return 0;
    }

    if (0 >= IszY) {
        printf("dimY must be > 0\n");
        return 0;
    }

    if (sscanf(argv[6], "%d", &Nfr) == EOF) {
        printf("ERROR: Number of frames input is incorrect");
        return 0;
    }

    if (0 >= Nfr) {
        printf("number of frames must be > 0\n");
        return 0;
    }

    if (sscanf(argv[8], "%d", &Nparticles) == EOF) {
        printf("ERROR: Number of particles input is incorrect");
        return 0;
    }

    if (0 >= Nparticles) {
        printf("Number of particles must be > 0\n");
        return 0;
    }

    int *seed = (int *)malloc(sizeof(int) * (size_t)Nparticles);
    int i;
    for (i = 0; Nparticles > i; i++)
        seed[i] = (int)time(0) * i;

    unsigned char *I = (unsigned char *)malloc(sizeof(unsigned char) * (size_t)IszX * IszY * Nfr);
    long long start = get_time();

    videoSequence(I, IszX, IszY, Nfr, seed);
    long long endVideoSequence = get_time();
    printf("VIDEO SEQUENCE TOOK %f\n", elapsed_time(start, endVideoSequence));

    particleFilter(I, IszX, IszY, Nfr, seed, Nparticles);
    long long endParticleFilter = get_time();
    printf("PARTICLE FILTER TOOK %f\n", elapsed_time(endVideoSequence, endParticleFilter));
    printf("ENTIRE PROGRAM TOOK %f\n", elapsed_time(start, endParticleFilter));

    free(seed);
    free(I);
    return 0;
}
